using System.Diagnostics;

public class Solution
{
    public int BestRotation0(int[] nums)
    {
        int n = nums.Length;
        int maxScore = 0;
        int res = -1;
        for (int k = 0; k < n; k++)
        {
            int score = 0;
            for (int i = 0; i < n; i++)
            {
                if (nums[i] <= (i - k + n) % n)
                {
                    score++;
                }
            }
            if (score > maxScore)
            {
                maxScore = score;
                res = k;
            }
        }
        return res;
    }

    public int BestRotation(int[] nums)
    {
        int n = nums.Length;
        int[] turningPoints = new int[n];   // how many points we will lose when k reaches this point
        for (int i = 0; i < n; i++)
        {
            turningPoints[(i - nums[i] + 1 + n) % n] -= 1;  // we lost point for nums[i] when k = (i - nums[i] + 1) % n
        }
        int bestk = 0;
        for (int k = 1; k < n; k++)
        {
            // for such shift we have already lost turningPoints[k - 1] points,
            // and we are additionally losing turningPoints[k] points,
            // but we also gain 1 point for the shift
            turningPoints[k] += turningPoints[k - 1] + 1;
            if (turningPoints[k] > turningPoints[bestk])
            {
                bestk = k;
            }
        }
        return bestk;
    }
}

